from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression or field is invalid."""


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class CronField:
    spec: FieldSpec
    original: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return len(self.values) == self.spec.maximum - self.spec.minimum + 1

    def is_single_value(self) -> bool:
        return len(self.values) == 1

    def single_value(self) -> int:
        if not self.is_single_value():
            raise CronParseError(f"{self.spec.name} is not a single value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
