def parse_cron(expression: str) -> CronSchedule:
    return CronSchedule.parse(expression)


def parse_field(raw: str, spec: FieldSpec) -> CronField:
    if not raw:
        raise CronParseError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for part in raw.split(","):
        if not part:
            raise CronParseError(f"Empty list item in {spec.name} field: {raw!r}")
        values.update(parse_field_part(part, spec))

    return CronField(spec=spec, original=raw, values=tuple(sorted(values)))


def parse_field_part(part: str, spec: FieldSpec) -> set[int]:
    base, step = split_step(part, spec)
    values = parse_base(base, spec)

    if step is None:
        return values

    ordered = sorted(values)
    return set(ordered[::step])


def split_step(part: str, spec: FieldSpec) -> tuple[str, int | None]:
    if "/" not in part:
        return part, None

    pieces = part.split("/")
    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid step syntax in {spec.name} field: {part!r}")

    step = parse_int(pieces[1], spec.name)

    if step <= 0:
        raise CronParseError(f"Step must be positive in {spec.name} field: {part!r}")

    return pieces[0], step


def parse_base(base: str, spec: FieldSpec) -> set[int]:
    if base == "*":
        return set(range(spec.minimum, spec.maximum + 1))

    if "-" in base:
        return parse_range(base, spec)

    value = parse_int(base, spec.name)
    validate_value(value, spec)
    return {value}


def parse_range(raw_range: str, spec: FieldSpec) -> set[int]:
    pieces = raw_range.split("-")
    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid range in {spec.name} field: {raw_range!r}")

    start = parse_int(pieces[0], spec.name)
    end = parse_int(pieces[1], spec.name)

    validate_value(start, spec)
    validate_value(end, spec)

    if start > end:
        raise CronParseError(
            f"Range start cannot be greater than end in {spec.name} field: {raw_range!r}"
        )

    return set(range(start, end + 1))


def parse_int(raw: str, field_name: str) -> int:
    if not raw.isdigit():
        raise CronParseError(f"Expected integer in {field_name} field, got {raw!r}")
    return int(raw)


def validate_value(value: int, spec: FieldSpec) -> None:
    if not spec.minimum <= value <= spec.maximum:
        raise CronParseError(
            f"{spec.name} value {value} is outside allowed range "
            f"{spec.minimum}-{spec.maximum}"
        )


def is_simple_step(raw: str) -> bool:
    return raw.startswith("*/") and raw.count("/") == 1


def parse_simple_step(raw: str) -> int:
    return int(raw.split("/", 1)[1])


