    if field.is_single_value():
        return f"on the {ordinal(field.single_value())} of every month"

    return f"on the {format_values(field.values, ordinal)} of every month"


def describe_month(field: CronField) -> str:
    if field.is_single_value():
        return f"in {MONTH_NAMES[field.single_value()]}"

    return f"in {format_values(field.values, lambda value: MONTH_NAMES[value])}"


