def is_contiguous(values: tuple[int, ...]) -> bool:
    if len(values) < 2:
        return False
    return list(values) == list(range(values[0], values[-1] + 1))


def format_values(
    values: Iterable[int],
    formatter: callable[[int], str] = str,
) -> str:
    items = [formatter(value) for value in values]

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


